import { Link, useNavigate } from "react-router-dom";
import { useEffect, useState } from "react";

export default function Navbar() {
  const navigate = useNavigate();
  const [isLogged, setIsLogged] = useState(!!localStorage.getItem("token"));

  useEffect(() => {
    const syncAuth = () => {
      setIsLogged(!!localStorage.getItem("token"));
    };

    window.addEventListener("storage", syncAuth);
    return () => window.removeEventListener("storage", syncAuth);
  }, []);

  const logout = () => {
    localStorage.clear();
    setIsLogged(false);
    navigate("/login");
  };

  return (
    <nav style={{ padding: 10, background: "#222", color: "#fff" }}>
      <Link to="/" style={{ color: "#fff", marginRight: 10 }}>Home</Link>

      {isLogged ? (
        <>
          <Link to="/vehicles" style={{ color: "#fff", marginRight: 10 }}>Vehicles</Link>
          <Link to="/appointments" style={{ color: "#fff", marginRight: 10 }}>Appointments</Link>
          <button onClick={logout} style={{ padding: "5px 10px" }}>
            Logout
          </button>
        </>
      ) : (
        <>
          <Link to="/login" style={{ color: "#fff", marginRight: 10 }}>Login</Link>
          <Link to="/register" style={{ color: "#fff" }}>Register</Link>
        </>
      )}
    </nav>
  );
}
